import re

class Token:
    """Representa un token en una expresión matemática."""
    def __init__(self, tipo, valor):
        self.tipo = tipo
        self.valor = valor

    def __repr__(self):
        """Retorna una representación string del token."""
        return f"Token({self.tipo}, {self.valor})"


class Tokenizador:
    """Tokeniza una expresión matemática."""
    def __init__(self, expresion):
        self.expresion = expresion
        self.posicion = 0

    def obtener_token(self):
        """Obtiene el siguiente token en la expresión."""
        if self.posicion >= len(self.expresion):
            return Token("EOF", None)

        if self.expresion[self.posicion].isspace():
            self.posicion += 1
            return self.obtener_token()

        if self.expresion[self.posicion].isdigit() or self.expresion[self.posicion] == ".":
            match = re.match(r"(\d+(?:\.\d+)?)", self.expresion[self.posicion:])
            if match:
                valor = match.group(1)
                self.posicion += len(valor)
                return Token("NUMERO", float(valor) if "." in valor else int(valor))

        if self.expresion[self.posicion] in "+-*/()":
            valor = self.expresion[self.posicion]
            self.posicion += 1
            return Token("OPERADOR", valor)

        raise ValueError(f"Caracter no válido en la posición {self.posicion}: {self.expresion[self.posicion]}")

    def tokenizar(self):
        """Tokeniza la expresión matemática."""
        tokens = []
        while True:
            token = self.obtener_token()
            if token.tipo == "EOF":
                break
            tokens.append(token)
        return tokens


def main():
    expresion = "2 + 3 * (4 - 1)"
    tokenizador = Tokenizador(expresion)
    tokens = tokenizador.tokenizar()
    print(tokens)


if __name__ == "__main__":
    main()
