def is_balanced(cadena: str) -> bool:
    """
    Verifica si una cadena de caracteres tiene un balanceo adecuado de paréntesis, 
    corchetes y llaves.

    Args:
        cadena (str): La cadena a verificar.

    Returns:
        bool: True si la cadena está balanceada, False de lo contrario.

    Raises:
        TypeError: Si la entrada no es una cadena.
        ValueError: Si la cadena contiene caracteres no válidos.
    """

    if not isinstance(cadena, str):
        raise TypeError("La entrada debe ser una cadena")

    if cadena is None:
        raise ValueError("La cadena no puede ser None")

    MAPEO = {")": "(", "}": "{", "]": "["}
    pila = []

    for char in cadena:
        if char in MAPEO.values():
            pila.append(char)
        elif char in MAPEO.keys():
            if not pila or MAPEO[char] != pila.pop():
                return False
        elif not char.isspace() and not char.isalnum():
            raise ValueError("La cadena contiene caracteres no válidos")

    return not pila
