from typing import Callable, Dict, List, Optional

class EventManager:
    def __init__(self):
        self.events: Dict[str, List[Callable]] = {}

    def on(self, event: str, callback: Callable) -> None:
        """
        Registra un callback para un evento.

        Args:
        - event (str): El nombre del evento.
        - callback (Callable): La función a llamar cuando se dispare el evento.
        """
        if not isinstance(event, str) or not event:
            raise ValueError("El evento debe ser un string no vacío")
        if not callable(callback):
            raise ValueError("El callback debe ser una función")

        if event not in self.events:
            self.events[event] = []
        self.events[event].append(callback)

    def off(self, event: str, callback: Callable) -> None:
        """
        Elimina un callback para un evento.

        Args:
        - event (str): El nombre del evento.
        - callback (Callable): La función a eliminar.
        """
        if not isinstance(event, str) or not event:
            raise ValueError("El evento debe ser un string no vacío")
        if not callable(callback):
            raise ValueError("El callback debe ser una función")

        if event not in self.events:
            raise ValueError("El evento no existe")
        if callback not in self.events[event]:
            raise ValueError("El callback no existe para este evento")

        self.events[event].remove(callback)

    def emit(self, event: str, *args, **kwargs) -> None:
        """
        Dispara un evento y llama a todos los callbacks registrados.

        Args:
        - event (str): El nombre del evento.
        - *args: Argumentos a pasar a los callbacks.
        - **kwargs: Argumentos keyword a pasar a los callbacks.
        """
        if not isinstance(event, str) or not event:
            raise ValueError("El evento debe ser un string no vacío")

        if event not in self.events:
            return

        for callback in self.events[event]:
            callback(*args, **kwargs)

def main():
    # Ejemplo de uso
    event_manager = EventManager()

    def callback1():
        print("Callback 1")

    def callback2():
        print("Callback 2")

    event_manager.on("evento", callback1)
    event_manager.on("evento", callback2)

    event_manager.emit("evento")

    event_manager.off("evento", callback1)

    event_manager.emit("evento")

if __name__ == "__main__":
