class EventEmitter {
  /**
   * Constructor para el EventEmitter.
   */
  constructor() {
    // Inicializa un objeto para almacenar los listeners de cada evento.
    this.listeners = {};
  }

  /**
   * Agrega un listener para un evento específico.
   * @param {string} evento - El nombre del evento.
   * @param {function} callback - La función que se ejecutará cuando se emita el evento.
   */
  agregarListener(evento, callback) {
    if (!evento || !callback) {
      throw new Error('Evento y callback son requeridos');
    }

    // Si el evento no tiene listeners, crea un arreglo para almacenarlos.
    if (!this.listeners[evento]) {
      this.listeners[evento] = [];
    }

    // Agrega el callback al arreglo de listeners del evento.
    this.listeners[evento].push(callback);
  }

  /**
   * Emite un evento y ejecuta todos los listeners asociados.
   * @param {string} evento - El nombre del evento.
   * @param {...*} args - Argumentos que se pasarán a los listeners.
   */
  emitirEvento(evento, ...args) {
    if (!evento) {
      throw new Error('Evento es requerido');
    }

    // Si el evento tiene listeners, ejecuta cada uno de ellos con los argumentos proporcionados.
    if (this.listeners[evento]) {
      this.listeners[evento].forEach(callback => callback(...args));
    }
  }

  /**
   * Elimina un listener para un evento específico.
   * @param {string} evento - El nombre del evento.
   * @param {function} callback - La función que se eliminará como listener.
   */
  eliminarListener(evento, callback) {
    if (!evento || !callback) {
      throw new Error('Evento y callback son requeridos');
    }

    // Si el evento tiene listeners, busca y elimina el callback especificado.
    if (this.listeners[evento]) {
      this.listeners[evento] = this.listeners[evento].filter(cb => cb !== callback);
    } else {
      throw new Error(`No hay listeners para el evento '${evento}'`);
    }
  }
}

// Ejemplo de uso
const emitter = new EventEmitter();

// Agrega un listener para 'evento1'
emitter.agregarListener('evento1', () => console.log('Este mensaje debería ser escuchado'));

// Emite 'evento1'
emitter.emitirEvento('evento1');

// Agrega y elimina un listener para 'evento1'
emitter.agregarListener('evento1', () => console.log('Este mensaje no debería ser escuchado'));
emitter.eliminarListener('evento1', () => console.log('Este mensaje no debería ser escuchado'));

// Emite 'evento1' nuevamente
emitter.emitirEvento('evento1');
