from functools import wraps
from typing import Tuple, Type, Callable, Any
import time
import random

def retry(
    max_retries: int = 3,
    backoff_factor: float = 0.5,
    exceptions: Tuple[Type[Exception], ...] = (Exception,)
) -> Callable:
    """
    Decorador para reintentar una función en caso de fallo.

    Args:
    - max_retries: Número máximo de reintentos.
    - backoff_factor: Factor de retardo entre reintentos.
    - exceptions: Tupla de tipos de excepciones que se deben reintentar.

    Returns:
    - Un decorador que reintenta la función decorada en caso de fallo.
    """

    if max_retries < 0:
        raise ValueError("max_retries debe ser mayor o igual a 0")
    if backoff_factor <= 0:
        raise ValueError("backoff_factor debe ser mayor que 0")
    if not exceptions:
        raise ValueError("exceptions no puede ser vacía")

    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            retries = 0
            delay = 0
            while retries <= max_retries:
                try:
                    return func(*args, **kwargs)
                except exceptions as error:
                    if retries < max_retries:
                        delay = backoff_factor * (2 ** retries)
                        delay_with_jitter = delay * (1 + random.random() * 0.1)
                        time.sleep(delay_with_jitter)
                        retries += 1
                    else:
                        raise error
        return wrapper
    return decorator

@retry(max_retries=3, backoff_factor=0.5, exceptions=(Exception,))
def ejemplo_de_funcion() -> None:
    # Simulación de una función que puede fallar
    import random
    if random.random() < 0.5:
        raise Exception("Error simulado")
    print("Función ejecutada con éxito")

# Ejemplo de uso
if __name__ == "__main__":
    ejemplo_de_funcion()
