from typing import Optional

class Nodo:
    """Representa un nodo en el árbol binario."""
    def __init__(self, valor: int):
        """Inicializa un nodo con un valor."""
        self.valor = valor
        self.izquierda: Optional[Nodo] = None
        self.derecha: Optional[Nodo] = None

class ArbolBinario:
    """Representa un árbol binario."""
    def __init__(self, raiz: Nodo):
        """Inicializa un árbol binario con una raíz."""
        if not isinstance(raiz, Nodo):
            raise ValueError("La raíz debe ser un objeto Nodo")
        self.raiz = raiz

    def insertar(self, valor: int) -> None:
        """Inserta un valor en el árbol binario."""
        if not isinstance(valor, int):
            raise ValueError("El valor debe ser un número entero")
        self._insertar_recursivo(self.raiz, valor)

    def _insertar_recursivo(self, nodo: Nodo, valor: int) -> None:
        """Inserta un valor en el árbol binario de manera recursiva."""
        if valor < nodo.valor:
            if nodo.izquierda is None:
                nodo.izquierda = Nodo(valor)
            else:
                self._insertar_recursivo(nodo.izquierda, valor)
        else:
            if nodo.derecha is None:
                nodo.derecha = Nodo(valor)
            else:
                self._insertar_recursivo(nodo.derecha, valor)

    def recorrer_en_nivel(self) -> list[int]:
        """Recorre el árbol binario en nivel y devuelve los valores."""
        resultado: list[int] = []
        cola: list[Nodo] = [self.raiz]
        while cola:
            nodo = cola.pop(0)
            resultado.append(nodo.valor)
            if nodo.izquierda:
                cola.append(nodo.izquierda)
            if nodo.derecha:
                cola.append(nodo.derecha)
        return resultado

# Ejemplo de uso
if __name__ == "__main__":
    raiz = Nodo(5)
    arbol = ArbolBinario(raiz)
    arbol.insertar(3)
    arbol.insertar(7)
    arbol.insertar(2)
    arbol.insertar(4)
    arbol.insertar(6)
    arbol.insertar(8)
    print(arbol.recorrer_en_nivel())  # [5, 3, 7, 2, 4, 6, 8]
```

