def puentes_de_palabras(lista_palabras: list, maximo_conexiones_permitidas: int) -> list:
    """
    Esta función encuentra los puentes de palabras en una lista de palabras.

    Un puente de palabras es una secuencia de palabras en la que cada palabra 
    se diferencia de la anterior en solo una letra.

    Parameters:
    lista_palabras (list): La lista de palabras a procesar.
    maximo_conexiones_permitidas (int): El máximo número de conexiones permitidas.

    Returns:
    list: La lista de puentes de palabras encontrados.
    """
    if maximo_conexiones_permitidas <= 0:
        raise ValueError("El máximo número de conexiones permitidas debe ser mayor que 0")

    if not lista_palabras:
        return []

    grafo_de_palabras = {}
    for palabra in lista_palabras:
        grafo_de_palabras[palabra] = []
        for otra_palabra in lista_palabras:
            if palabra != otra_palabra and sum(a != b for a, b in zip(palabra, otra_palabra)) == 1:
                grafo_de_palabras[palabra].append(otra_palabra)

    def conectar_palabras(palabra_actual: str, camino_actual: list, maximo_conexiones: int) -> list:
        if maximo_conexiones == 0:
            return [camino_actual]

        caminos_posibles = []
        for palabra_siguiente in grafo_de_palabras[palabra_actual]:
            if palabra_siguiente not in camino_actual:
                caminos_posibles.extend(conectar_palabras(palabra_siguiente, camino_actual + [palabra_siguiente], maximo_conexiones - 1))

        return caminos_posibles

    puentes_encontrados = []
    for palabra_inicial in lista_palabras:
        puentes_encontrados.extend(conectar_palabras(palabra_inicial, [palabra_inicial], maximo_conexiones_permitidas))

    return puentes_encontrados
