import re
from typing import List

class Token:
    def __init__(self, tipo: str, valor: str):
        if tipo not in ["numero", "operador", "parentesis"]:
            raise ValueError("Tipo de token inválido")
        self.tipo = tipo
        self.valor = valor

    def __eq__(self, otro):
        return self.tipo == otro.tipo and self.valor == otro.valor

    def __repr__(self):
        return f"Token({self.tipo}, {self.valor})"

class Tokenizer:
    def __init__(self, *, expresion: str):
        self.expresion = expresion.strip()
        self.posicion = 0

    def obtener_siguiente_token(self) -> Token:
        if self.posicion >= len(self.expresion):
            raise ValueError("Fin de la expresión")

        if self.expresion[self.posicion].isspace():
            self.posicion += 1
            return self.obtener_siguiente_token()

        if self.expresion[self.posicion].isdigit() or self.expresion[self.posicion] == ".":
            match = re.match(r"(\d+(?:\.\d+)?)(?:[eE][+-]?\d+)?", self.expresion[self.posicion:])
            if match:
                valor = match.group(1)
                self.posicion += len(valor)
                return Token("numero", valor)
            else:
                raise ValueError("Número inválido")

        if self.expresion[self.posicion] in "+-*/()":
            valor = self.expresion[self.posicion]
            self.posicion += 1
            if valor in "+-*/":
                return Token("operador", valor)
            else:
                return Token("parentesis", valor)

        raise ValueError("Carácter inválido")

    def tokenizar(self) -> List[Token]:
        tokens = []
        while self.posicion < len(self.expresion):
            try:
                token = self.obtener_siguiente_token()
                tokens.append(token)
            except ValueError as e:
                raise ValueError(f"Error en la expresión: {e}")
        return tokens

def main():
    expresion = "2 + 3 * (4 - 1)"
    tokenizer = Tokenizer(expresion=expresion)
    tokens = tokenizer.tokenizar()
    print(tokens)

if __name__ == "__main__":
    main()
