interface Callback {
  (evento: string, ...args: any[]): void;
}

class Observador {
  private observadores: Map<string, Set<Callback>>;

  constructor() {
    this.observadores = new Map();
  }

  agregarObservador(evento: string, callback: Callback): void {
    if (!callback) {
      throw new Error('Callback no puede ser null o undefined');
    }

    if (!this.observadores.has(evento)) {
      this.observadores.set(evento, new Set());
    }

    this.observadores.get(evento)?.add(callback);
  }

  eliminarObservador(evento: string, callback: Callback): void {
    if (!callback) {
      throw new Error('Callback no puede ser null o undefined');
    }

    if (this.observadores.has(evento)) {
      const callbacks = this.observadores.get(evento);
      if (callbacks?.has(callback)) {
        callbacks.delete(callback);
      } else {
        console.warn(`Intentando eliminar un observador que no existe para el evento ${evento}`);
      }
    }
  }

  notificar(evento: string, ...args: any[]): void {
    if (!this.observadores.has(evento)) {
      console.warn(`Intentando notificar un evento que no existe: ${evento}`);
      return;
    }

    const callbacks = this.observadores.get(evento);
    if (callbacks) {
      for (const callback of callbacks) {
        try {
          callback(evento, ...args);
        } catch (error) {
          console.error(`Error al notificar el evento ${evento}: ${error.message}`);
        }
      }
    }
  }
}
