import networkx as nx
from typing import Dict, List, Tuple, Optional

class RedDeFlujo:
    def __init__(self):
        self.grafo: nx.DiGraph = nx.DiGraph()
        self.nodos: Dict[str, None] = {}
        self.conexiones: Dict[Tuple[str, str], float] = {}

    def agregar_nodo(self, nombre_nodo: str) -> None:
        """Agrega un nodo a la red de flujo."""
        if not nombre_nodo:
            raise ValueError("El nombre del nodo no puede ser vacío")
        if nombre_nodo not in self.nodos:
            self.nodos[nombre_nodo] = None
            self.grafo.add_node(nombre_nodo)

    def conectar_nodos(self, nodo_origen: str, nodo_destino: str, resistencia: float) -> None:
        """Conecta dos nodos en la red de flujo."""
        if not nodo_origen or not nodo_destino:
            raise ValueError("Los nombres de los nodos no pueden ser vacíos")
        if nodo_origen not in self.nodos or nodo_destino not in self.nodos:
            raise ValueError("Ambos nodos deben existir en la red")
        if resistencia < 0:
            raise ValueError("La resistencia no puede ser negativa")
        if (nodo_origen, nodo_destino) not in self.conexiones:
            self.conexiones[(nodo_origen, nodo_destino)] = resistencia
            self.grafo.add_edge(nodo_origen, nodo_destino, capacity=1 / resistencia)

    def desconectar_nodos(self, nodo_origen: str, nodo_destino: str) -> None:
        """Desconecta dos nodos en la red de flujo."""
        if not nodo_origen or not nodo_destino:
            raise ValueError("Los nombres de los nodos no pueden ser vacíos")
        if (nodo_origen, nodo_destino) in self.conexiones:
            del self.conexiones[(nodo_origen, nodo_destino)]
            if self.grafo.has_edge(nodo_origen, nodo_destino):
                self.grafo.remove_edge(nodo_origen, nodo_destino)

    def calcular_flujo(self, nodo_fuente: str, nodo_sumidero: str) -> float:
        """Calcula el flujo máximo en la red de flujo."""
        if not nodo_fuente or not nodo_sumidero:
            raise ValueError("Los nombres de los nodos no pueden ser vacíos")
        if nodo_fuente not in self.nodos or nodo_sumidero not in self.nodos:
            raise ValueError("Ambos nodos deben existir en la red")
        if not self.grafo.has_node(nodo_fuente) or not self.grafo.has_node(nodo_sumidero):
            raise ValueError("Ambos nodos deben existir en el grafo")
        if not nx.is_directed(self.grafo):
            raise ValueError("El grafo debe ser dirigido")
        flujo_maximo, _ = nx.maximum_flow(self.grafo, nodo_fuente, nodo_sumidero)
        return flujo_maximo

    def encontrar_camino_mayor_flujo(self, nodo_fuente: str, nodo_sumidero: str) -> List[str]:
        """Encuentra el camino de mayor flujo en la red de flujo."""
        if not nodo_fuente or not nodo_sumidero:
            raise ValueError("Los nombres de los nodos no pueden ser vacíos")
        if nodo_fuente not in self.nodos or nodo_sumidero not in self.nodos:
            raise ValueError("Ambos nodos deben existir en la red")
        if not self.grafo.has_node(nodo_fuente) or not self.grafo.has_node(nodo_sumidero):
            raise ValueError("Ambos nodos deben existir en el grafo")
        flujo_maximo, flujo_por_arista = nx.maximum_flow(self.grafo, nodo_fuente, nodo_sumidero)
        camino_mayor_flujo = []
        nodo_actual = nodo_sumidero
        while nodo_actual != nodo_fuente:
            for nodo_anterior in self.grafo.predecessors(nodo_actual):
                if flujo_por_arista[nodo_anterior][nodo_actual] > 0:
                    camino_mayor_flujo.insert(0, nodo_anterior)
                    nodo_actual = nodo_anterior
                    break
        camino_mayor_flujo.append(nodo_sumidero)
        return camino_mayor_flujo
