from typing import Dict, List, Set

def tiene_ciclo(grafo: Dict[int, List[int]]) -> bool:
    """
    Verifica si un grafo dirigido tiene un ciclo.

    Args:
    grafo: Un diccionario donde las claves son los nodos y los valores son listas de nodos adyacentes.

    Returns:
    True si el grafo tiene un ciclo, False en caso contrario.
    """
    if not isinstance(grafo, dict):
        raise ValueError("El grafo debe ser un diccionario")
    for nodo, adyacentes in grafo.items():
        if not isinstance(adyacentes, list) or not all(isinstance(n, int) for n in adyacentes):
            raise ValueError("Los valores del grafo deben ser listas de enteros")

    if not grafo:
        return False

    visitados: Set[int] = set()
    pila_llamadas: Set[int] = set()

    def dfs(nodo: int) -> bool:
        """
        Realiza una búsqueda en profundidad para detectar ciclos.

        Args:
        nodo: El nodo actual.

        Returns:
        True si se encuentra un ciclo, False en caso contrario.
        """
        visitados.add(nodo)
        pila_llamadas.add(nodo)

        for adyacente in grafo.get(nodo, []):
            if adyacente not in visitados:
                if dfs(adyacente):
                    return True
            elif adyacente in pila_llamadas:
                return True

        pila_llamadas.remove(nodo)
