from typing import List, Optional

def es_subanagrama(palabra1: str, palabra2: str) -> bool:
    """
    Verifica si palabra1 es un subanagrama de palabra2.

    Un subanagrama es una secuencia de caracteres que aparecen en el mismo orden
    en la otra palabra, pero no necesariamente consecutivos.

    :param palabra1: La palabra a verificar.
    :param palabra2: La palabra en la que se busca el subanagrama.
    :return: True si palabra1 es un subanagrama de palabra2, False en caso contrario.
    """
    if not palabra1 or not palabra2:
        return False

    indice = 0
    for char in palabra2:
        if indice < len(palabra1) and char == palabra1[indice]:
            indice += 1

    return indice == len(palabra1)


def encontrar_subanagramas(texto: Optional[str]) -> List[str]:
    """
    Encuentra todos los subanagramas en un texto.

    Un subanagrama es una secuencia de caracteres que aparecen en el mismo orden
    en la otra palabra, pero no necesariamente consecutivos.

    :param texto: El texto en el que se buscan los subanagramas.
    :return: Una lista de palabras que son subanagramas en el texto.
    """
    if not texto:
        return []

    palabras = texto.split()
    subanagramas = []

    for i in range(len(palabras)):
        for j in range(len(palabras)):
            if i != j and es_subanagrama(palabras[i], palabras[j]):
                subanagramas.append(palabras[i])

    return subanagramas


def encontrar_subanagramas_optimizado(texto: Optional[str]) -> List[str]:
    """
    Encuentra todos los subanagramas en un texto de manera optimizada.

    Un subanagrama es una secuencia de caracteres que aparecen en el mismo orden
    en la otra palabra, pero no necesariamente consecutivos.

    :param texto: El texto en el que se buscan los subanagramas.
    :return: Una lista de palabras que son subanagramas en el texto.
    """
    if not texto:
        return []

    palabras = texto.split()
    subanagramas = set()

    for palabra1 in palabras:
        for palabra2 in palabras:
            if palabra1 != palabra2 and es_subanagrama(palabra1, palabra2):
                subanagramas.add(palabra1)

    return list(subanagramas)
