def longest_common_subsequence(str1: str, str2: str) -> str:
    """
    Calcula la subsecuencia común más larga entre dos cadenas de caracteres.

    Args:
        str1 (str): La primera cadena de caracteres.
        str2 (str): La segunda cadena de caracteres.

    Returns:
        str: La subsecuencia común más larga.

    Raises:
        TypeError: Si str1 o str2 no son cadenas de caracteres.
    """
    if not isinstance(str1, str) or not isinstance(str2, str):
        raise TypeError("Ambas entradas deben ser cadenas de caracteres")

    len_str1 = len(str1)
    len_str2 = len(str2)

    if len_str1 == 0 or len_str2 == 0:
        return ""

    # Inicializa la matriz de programación dinámica
    dp = [[0] * (len_str2 + 1) for _ in range(len_str1 + 1)]

    # Rellena la matriz de programación dinámica
    for i in range(1, len_str1 + 1):
        for j in range(1, len_str2 + 1):
            if str1[i - 1] == str2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Reconstruye la subsecuencia común más larga
    lcs = []
    i, j = len_str1, len_str2
    while i > 0 and j > 0:
        if str1[i - 1] == str2[j - 1]:
            lcs.append(str1[i - 1])
            i -= 1
            j -= 1
        elif dp[i - 1][j] > dp[i][j - 1]:
            i -= 1
        else:
            j -= 1

    return "".join(reversed(lcs))


