class Nodo:
    """Representa un nodo en el árbol binario."""
    def __init__(self, valor):
        """Inicializa un nodo con un valor."""
        self.valor = valor
        self.izquierda = None
        self.derecha = None

class ArbolBinario:
    """Representa un árbol binario."""
    def __init__(self):
        """Inicializa un árbol binario vacío."""
        self.raiz = None

    def agregar_nodo(self, valor):
        """
        Agrega un nodo con el valor dado al árbol binario.

        Args:
            valor: El valor a agregar al árbol.

        Raises:
            TypeError: Si el valor no es del tipo correcto.
            ValueError: Si el valor es None o ya existe en el árbol.
        """
        if valor is None:
            raise ValueError("No se puede agregar None al árbol")
        if not isinstance(valor, (int, float)):
            raise TypeError("El valor debe ser un número")
        if self.raiz is None:
            self.raiz = Nodo(valor)
        else:
            self._agregar_nodo_recursivo(self.raiz, valor)

    def _agregar_nodo_recursivo(self, nodo, valor):
        """Recursivamente agrega un nodo al árbol."""
        if valor < nodo.valor:
            if nodo.izquierda is None:
                nodo.izquierda = Nodo(valor)
            else:
                self._agregar_nodo_recursivo(nodo.izquierda, valor)
        elif valor > nodo.valor:
            if nodo.derecha is None:
                nodo.derecha = Nodo(valor)
            else:
                self._agregar_nodo_recursivo(nodo.derecha, valor)
        else:
            raise ValueError("El valor ya existe en el árbol")

    def level_order_traversal(self):
        """
        Realiza un recorrido en orden de nivel del árbol.

        Returns:
            Una lista con los valores de los nodos en orden de nivel.
        """
        if self.raiz is None:
            return []
        resultado = []
        cola = [self.raiz]
        while cola:
            nodo = cola.pop(0)
            resultado.append(nodo.valor)
            if nodo.izquierda:
                cola.append(nodo.izquierda)
            if nodo.derecha:
                cola.append(nodo.derecha)
        return resultado

# Ejemplo de uso
arbol = ArbolBinario()
arbol.agregar_nodo(5)
arbol.agregar_nodo(3)
arbol.agregar_nodo(7)
arbol.agregar_nodo(2)
arbol.agregar_nodo(4)
arbol.agregar_nodo(6)
arbol.agregar_nodo(8)
print(arbol.level_order_traversal())  # [5, 3, 7, 2, 4, 6, 8]
