from enum import Enum
from typing import Iterator, List, Tuple

class TokenType(Enum):
    NUMERO = 1
    OPERADOR = 2
    PARENTESIS = 3

class Token:
    def __init__(self, tipo: TokenType, valor: str, posicion: int):
        self.tipo = tipo
        self.valor = valor
        self.posicion = posicion

    def __repr__(self):
        return f"Token({self.tipo}, {self.valor}, {self.posicion})"

class Tokenizador:
    def __init__(self, expresion: str):
        self.expresion = expresion
        self.posicion = 0

    def obtener_token(self) -> Token:
        if self.posicion >= len(self.expresion):
            return None

        if self.expresion[self.posicion].isspace():
            self.posicion += 1
            return self.obtener_token()

        if self.expresion[self.posicion].isdigit() or self.expresion[self.posicion] == '.':
            valor = ""
            while self.posicion < len(self.expresion) and (self.expresion[self.posicion].isdigit() or self.expresion[self.posicion] == '.'):
                valor += self.expresion[self.posicion]
                self.posicion += 1
            return Token(TokenType.NUMERO, valor, self.posicion - len(valor))

        if self.expresion[self.posicion] in "+-*/()":
            tipo = TokenType.OPERADOR if self.expresion[self.posicion] in "+-*/" else TokenType.PARENTESIS
            valor = self.expresion[self.posicion]
            self.posicion += 1
            return Token(tipo, valor, self.posicion - 1)

        raise ValueError(f"Caracter no reconocido en la posicion {self.posicion}")

    def tokenizar(self) -> Iterator[Token]:
        while True:
            token = self.obtener_token()
            if token is None:
                break
            yield token

def main():
    expresion = "2 + 3 * (4 - 1)"
    tokenizador = Tokenizador(expresion)
    for token in tokenizador.tokenizar():
        print(token)

if __name__ == "__main__":
    main()
