import heapq
from typing import Dict, List, Tuple

def dijkstra(grafo: Dict[str, Dict[str, int]], nodo_inicio: str) -> Dict[str, int]:
    """
    Implementación del algoritmo de Dijkstra para encontrar el camino más corto desde un nodo de inicio a todos los demás nodos en un grafo.

    Args:
    - grafo (Dict[str, Dict[str, int]]): Representación del grafo como un diccionario de diccionarios, donde cada clave es un nodo y su valor es otro diccionario con los nodos adyacentes y sus respectivos pesos.
    - nodo_inicio (str): Nodo desde el que se inicia la búsqueda.

    Returns:
    - Dict[str, int]: Diccionario con los caminos más cortos desde el nodo de inicio a todos los demás nodos.

    Raises:
    - ValueError: Si el grafo es vacío, si el nodo de inicio no existe en el grafo, o si el grafo contiene aristas con pesos negativos.
    """

    if not grafo:
        raise ValueError("El grafo no puede ser vacío")

    if nodo_inicio not in grafo:
        raise ValueError("El nodo de inicio no existe en el grafo")

    for nodo, adyacentes in grafo.items():
        for adyacente, peso in adyacentes.items():
            if peso < 0:
                raise ValueError("El grafo no puede contener aristas con pesos negativos")

    cola_de_prioridad: List[Tuple[int, str]] = [(0, nodo_inicio)]
    caminos_cortos: Dict[str, int] = {nodo_inicio: 0}

    while cola_de_prioridad:
        try:
            _, nodo_actual = heapq.heappop(cola_de_prioridad)

            for adyacente, peso in grafo[nodo_actual].items():
                distancia = caminos_cortos[nodo_actual] + peso

                if adyacente not in caminos_cortos or distancia < caminos_cortos[adyacente]:
                    caminos_cortos[adyacente] = distancia
                    heapq.heappush(cola_de_prioridad, (distancia, adyacente))

        except Exception as e:
            raise Exception(f"Error durante la ejecución: {str(e)}")

    return caminos_cortos
