class TokenBucket:
    def __init__(self, rate, capacity):
        if not isinstance(rate, (int, float)) or rate <= 0:
            raise ValueError("La tasa debe ser un número positivo")
        if not isinstance(capacity, (int, float)) or capacity <= 0:
            raise ValueError("La capacidad debe ser un número positivo")
        self.rate = rate
        self.capacity = capacity
        self.last_update = 0
        self.tokens = capacity

    def allow_request(self, timestamp):
        if not isinstance(timestamp, (int, float)) or timestamp < self.last_update:
            raise ValueError("La marca de tiempo debe ser un número no negativo y mayor o igual que la última actualización")
        elapsed_time = timestamp - self.last_update
        self.last_update = timestamp
        self.tokens = min(self.capacity, self.tokens + elapsed_time * self.rate)
        if self.tokens >= 1:
            self.tokens -= 1
            return True
        return False
