class EventEmitter {
  #listeners = {};

  /**
   * Registra un callback para un evento específico.
   * @param {string} eventName - Nombre del evento.
   * @param {function} callback - Función a ejecutar cuando se emita el evento.
   */
  on(eventName, callback) {
    if (typeof eventName !== 'string' || !eventName) {
      throw new Error('El nombre del evento debe ser una cadena no vacía');
    }

    if (typeof callback !== 'function') {
      throw new Error('El callback debe ser una función');
    }

    if (!this.#listeners[eventName]) {
      this.#listeners[eventName] = [];
    }

    this.#listeners[eventName].push(callback);
  }

  /**
   * Emite un evento y ejecuta los callbacks registrados.
   * @param {string} eventName - Nombre del evento.
   * @param {...*} args - Argumentos a pasar a los callbacks.
   */
  emit(eventName, ...args) {
    if (typeof eventName !== 'string' || !eventName) {
      throw new Error('El nombre del evento debe ser una cadena no vacía');
    }

    if (this.#listeners[eventName]) {
      this.#listeners[eventName].forEach((callback) => {
        callback(...args);
      });
    }
  }

  /**
   * Elimina un callback registrado para un evento específico.
   * @param {string} eventName - Nombre del evento.
   * @param {function} callback - Función a eliminar.
   */
  off(eventName, callback) {
    if (typeof eventName !== 'string' || !eventName) {
      throw new Error('El nombre del evento debe ser una cadena no vacía');
    }

    if (this.#listeners[eventName]) {
      this.#listeners[eventName] = this.#listeners[eventName].filter((cb) => cb !== callback);
    }
  }
}
