    def _crecer_recursivo(self, nodo, probabilidad_crecer, max_altura):
        if nodo.valor < max_altura and random.random() < probabilidad_crecer:
            nodo.valor += 1
            if nodo.izquierda is None:
                nodo.izquierda = Nodo(nodo.valor)
            if nodo.derecha is None:
                nodo.derecha = Nodo(nodo.valor)
        if nodo.izquierda is not None:
            self._crecer_recursivo(nodo.izquierda, probabilidad_crecer, max_altura)
        if nodo.derecha is not None:
            self._crecer_recursivo(nodo.derecha, probabilidad_crecer, max_altura)

    def __str__(self):
        if self.raiz is None:
            return "Árbol vacío"
