from typing import Dict, List, Set

def has_cycle(graph: Dict) -> bool:
    """
    Verifica si un grafo dirigido tiene ciclos.

    Args:
    graph: Un diccionario que representa el grafo, donde cada clave es un vértice
           y su valor es una lista de vecinos.

    Returns:
    True si el grafo tiene un ciclo, False en caso contrario.
    """

    if not isinstance(graph, dict):
        raise ValueError("El grafo debe ser un diccionario")

    visited: Set = set()
    stack: Set = set()

    def is_cyclic(vertex: str) -> bool:
        visited.add(vertex)
        stack.add(vertex)

        for neighbor in graph.get(vertex, []):
            if neighbor not in visited:
                if is_cyclic(neighbor):
                    return True
            elif neighbor in stack:
                return True

        stack.remove(vertex)
        return False

    for vertex in graph:
        if not isinstance(vertex, str):
            raise ValueError("Los vértices deben ser cadenas")
        if not isinstance(graph[vertex], list):
            raise ValueError("Los vecinos deben ser una lista")

        if vertex not in visited:
            if is_cyclic(vertex):
                return True

    return False
