from functools import wraps
from typing import Callable, Tuple, Type

def retry(
    max_retries: int = 3,
    backoff_factor: float = 0.5,
    exceptions: Tuple[Type[Exception], ...] = (Exception,)
) -> Callable:
    """
    Decorador para reintentar una función en caso de excepción.

    Args:
        max_retries (int): Número máximo de reintentos. Debe ser mayor que 0.
        backoff_factor (float): Factor de retardo para el tiempo de espera entre reintentos. Debe ser mayor que 0.
        exceptions (Tuple[Type[Exception], ...]): Tupla de excepciones que se deben reintentar.

    Raises:
        ValueError: Si max_retries es menor que 0 o backoff_factor es menor o igual a 0.
        TypeError: Si exceptions no es una tupla.
    """

    if max_retries < 0:
        raise ValueError("max_retries debe ser mayor que 0")
    if backoff_factor <= 0:
        raise ValueError("backoff_factor debe ser mayor que 0")
    if not isinstance(exceptions, tuple) or not all(issubclass(exc, Exception) for exc in exceptions):
        raise TypeError("exceptions debe ser una tupla de excepciones")

    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs):
            delay = 0
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt < max_retries:
                        delay = backoff_factor * (2 ** attempt) + random.uniform(0, 1)
                        time.sleep(delay)
                    else:
                        raise e
        return wrapper
    return decorator
