def level_order_traversal(raiz: Optional[Nodo]) -> list[int]:
    if not raiz:
        return []

    resultado = []
    cola = deque([raiz])

    while cola:
        nodo = cola.popleft()
        resultado.append(nodo.valor)

        if nodo.izquierda:
            cola.append(nodo.izquierda)
        if nodo.derecha:
            cola.append(nodo.derecha)

