import heapq

def dijkstra(grafo, origen):
    """
    Algoritmo de Dijkstra para calcular las distancias mínimas desde un nodo de origen a todos los demás nodos en un grafo.

    Parámetros:
    grafo (dict): Representación del grafo como un diccionario de adyacencia.
    origen (str): Nodo de origen.

    Retorna:
    dict: Diccionario con las distancias mínimas desde el nodo de origen a todos los demás nodos.

    Excepciones:
    ValueError: Si el nodo de origen no existe en el grafo.
    """

    if origen not in grafo:
        raise ValueError("El nodo de origen no existe en el grafo")

    distancias = {nodo: float('inf') for nodo in grafo}
    distancias[origen] = 0

    cola_prioridad = [(0, origen)]

    while cola_prioridad:
        distancia, nodo = heapq.heappop(cola_prioridad)

        if distancia > distancias[nodo]:
            continue

        for vecino, peso in grafo[nodo].items():
            if peso < 0:
                raise ValueError("El grafo no admite pesos negativos")

            distancia_vecino = distancia + peso

            if distancia_vecino < distancias[vecino]:
                distancias[vecino] = distancia_vecino
                heapq.heappush(cola_prioridad, (distancia_vecino, vecino))

    return distancias

def main():
    grafo = {
        'A': {'B': 1, 'C': 4},
        'B': {'A': 1, 'C': 2, 'D': 5},
        'C': {'A': 4, 'B': 2, 'D': 1},
        'D': {'B': 5, 'C': 1}
    }

    origen = 'A'
    distancias = dijkstra(grafo, origen)
    print(distancias)

