import re

class TokenType(Enum):
    NUMERO = 1
    OPERADOR = 2
    PARENTESIS = 3

class Token:
    def __init__(self, tipo, valor):
        self.tipo = tipo
        self.valor = valor

    def __repr__(self):
        return f"Token({self.tipo.name}, '{self.valor}')"

class Tokenizador:
    def __init__(self, expresion):
        self._expresion = expresion
        self._indice = 0

    def obtener_token(self):
        if self._indice >= len(self._expresion):
            return None

        # Ignorar espacios en blanco
        while self._indice < len(self._expresion) and self._expresion[self._indice].isspace():
            self._indice += 1

        # Número decimal
        match = re.match(r"\d+(?:\.\d+)?", self._expresion[self._indice:])
        if match:
            valor = match.group()
            self._indice += len(valor)
            return Token(TokenType.NUMERO, valor)

        # Operador
        if self._expresion[self._indice] in "+-*/":
            valor = self._expresion[self._indice]
            self._indice += 1
            return Token(TokenType.OPERADOR, valor)

        # Paréntesis
        if self._expresion[self._indice] in "()":
            valor = self._expresion[self._indice]
            self._indice += 1
            return Token(TokenType.PARENTESIS, valor)

        # Error: carácter no soportado
        raise ValueError(f"Carácter no soportado: '{self._expresion[self._indice]}'")

    def tokenizar(self):
        tokens = []
        while True:
            token = self.obtener_token()
            if token is None:
                break
            tokens.append(token)
        return tokens

