class EventEmitter {
  /**
   * Constructor para inicializar el objeto EventEmitter.
   */
  constructor() {
    /**
     * Objeto para almacenar los eventos y sus respectivos callbacks.
     * @type {Object<string, Array<Function>>}
     */
    this.events = {};
  }

  /**
   * Método para registrar un callback para un evento específico.
   * @param {string} eventName - Nombre del evento.
   * @param {Function} callback - Función callback a registrar.
   * @throws {Error} Si el evento o callback es inválido.
   */
  on(eventName, callback) {
    if (typeof eventName !== 'string' || eventName.trim() === '') {
      throw new Error('El nombre del evento es inválido');
    }
    if (typeof callback !== 'function') {
      throw new Error('El callback es inválido');
    }
    if (!this.events[eventName]) {
      this.events[eventName] = [];
    }
    this.events[eventName].push(callback);
  }

  /**
   * Método para eliminar un callback para un evento específico.
   * @param {string} eventName - Nombre del evento.
   * @param {Function} callback - Función callback a eliminar.
   * @throws {Error} Si el evento o callback es inválido.
   */
  off(eventName, callback) {
    if (typeof eventName !== 'string' || eventName.trim() === '') {
      throw new Error('El nombre del evento es inválido');
    }
    if (typeof callback !== 'function') {
      throw new Error('El callback es inválido');
    }
    if (this.events[eventName]) {
      this.events[eventName] = this.events[eventName].filter((cb) => cb !== callback);
    }
  }

  /**
   * Método para emitir un evento y ejecutar los callbacks registrados.
   * @param {string} eventName - Nombre del evento.
   * @param {...*} args - Argumentos a pasar a los callbacks.
   * @throws {Error} Si el evento es inválido.
   */
  emit(eventName, ...args) {
    if (typeof eventName !== 'string' || eventName.trim() === '') {
      throw new Error('El nombre del evento es inválido');
    }
    if (this.events[eventName]) {
      this.events[eventName].forEach((callback) => {
        try {
          callback(...args);
        } catch (error) {
          console.error(`Error al ejecutar callback para evento ${eventName}:`, error);
        }
      });
    }
  }
}

