class CircularBuffer:
    def __init__(self, capacidad: int):
        """Inicializa un búfer circular con la capacidad dada."""
        if not isinstance(capacidad, int) or capacidad < 0:
            raise ValueError("La capacidad debe ser un número entero no negativo")
        if capacidad == 0:
            raise ValueError("La capacidad no puede ser cero")
        self.capacidad = capacidad
        self.buffer = [None] * capacidad
        self.inicio = 0
        self.fin = 0
        self.tamaño = 0

    def append(self, elemento):
        """Agrega un elemento al final del búfer."""
        if self.tamaño == self.capacidad:
            self.inicio = (self.inicio + 1) % self.capacidad
        else:
            self.tamaño += 1
        self.buffer[self.fin] = elemento
        self.fin = (self.fin + 1) % self.capacidad

    def __len__(self):
        """Devuelve el número de elementos en el búfer."""
        return self.tamaño

    def __getitem__(self, índice):
        """Devuelve el elemento en la posición dada."""
        if índice < 0 or índice >= self.tamaño:
            raise IndexError("Índice fuera de rango")
        return self.buffer[(self.inicio + índice) % self.capacidad]
