def validar_balance(cadena: str) -> bool:
    """
    Verifica si una cadena de paréntesis, corchetes y llaves está balanceada.

    Args:
        cadena (str): La cadena a verificar.

    Returns:
        bool: True si la cadena está balanceada, False de lo contrario.

    Raises:
        TypeError: Si la entrada no es una cadena.
        ValueError: Si la cadena contiene caracteres no válidos.
    """
    if not isinstance(cadena, str):
        raise TypeError("La entrada debe ser una cadena")

    opening_to_closing_map = {")": "(", "}": "{", "]": "["}
    stack = []

    for char in cadena:
        if char in opening_to_closing_map.values():
            stack.append(char)
        elif char in opening_to_closing_map.keys():
            if not stack or stack.pop() != opening_to_closing_map[char]:
                return False
        elif not char.isspace():
            raise ValueError("La cadena contiene caracteres no válidos")

    return not stack
