    en_pila_de_llamadas = set()

    def dfs(nodo):
        visitados.add(nodo)
        en_pila_de_llamadas.add(nodo)

        for vecino in grafos.get(nodo, []):
            if vecino not in visitados:
                if dfs(vecino):
                    return True
            elif vecino in en_pila_de_llamadas:
                return True

        en_pila_de_llamadas.remove(nodo)
        return False

