def es_seguro(tablero, fila, columna, n):
    """
    Verifica si es seguro colocar una reina en la posición (fila, columna) del tablero.

    :param tablero: El tablero de ajedrez representado como una lista de listas.
    :param fila: La fila en la que se intenta colocar la reina.
    :param columna: La columna en la que se intenta colocar la reina.
    :param n: El tamaño del tablero.
    :return: True si es seguro colocar la reina, False de lo contrario.
    """
    # Verificar fila
    for i in range(n):
        if tablero[fila][i] == 1:
            return False

    # Verificar columna
    for i in range(n):
        if tablero[i][columna] == 1:
            return False

    # Verificar diagonal superior izquierda
    for i, j in zip(range(fila, -1, -1), range(columna, -1, -1)):
        if tablero[i][j] == 1:
            return False

    # Verificar diagonal superior derecha
    for i, j in zip(range(fila, -1, -1), range(columna, n)):
        if tablero[i][j] == 1:
            return False

    # Verificar diagonal inferior izquierda
    for i, j in zip(range(fila, n), range(columna, -1, -1)):
        if tablero[i][j] == 1:
            return False

    # Verificar diagonal inferior derecha
    for i, j in zip(range(fila, n), range(columna, n)):
        if tablero[i][j] == 1:
            return False

    return True


def colocar_reinas(tablero, fila, n):
    """
    Coloca reinas en el tablero utilizando backtracking.

    :param tablero: El tablero de ajedrez representado como una lista de listas.
    :param fila: La fila actual en la que se intenta colocar una reina.
    :param n: El tamaño del tablero.
    :yield: Una solución válida para el problema de las N-Reinas.
    """
    if fila == n:
        yield [fila[:] for fila in tablero]
    else:
        for columna in range(n):
            if es_seguro(tablero, fila, columna, n):
                tablero[fila][columna] = 1
                yield from colocar_reinas(tablero, fila + 1, n)
                tablero[fila][columna] = 0


def resolver_n_reinas(n):
    """
    Resuelve el problema de las N-Reinas.

    :param n: El tamaño del tablero.
    :return: Una lista de soluciones válidas para el problema de las N-Reinas.
    """
    if not isinstance(n, int) or n <= 0:
        raise ValueError("n debe ser un número entero positivo")

    tablero = [[0] * n for _ in range(n)]
    return list(colocar_reinas(tablero, 0, n))


# Ejemplo de uso
n = 4
soluciones = resolver_n_reinas(n)
for i, solucion in enumerate(soluciones):
    print(f"Solución {i + 1}:")
    for fila in solucion:
        print(fila)
    print()
