import logging
import random
import time
from functools import wraps

def retry(
    exceptions: tuple,
    max_retries: int = 3,
    backoff_factor: float = 0.5,
    logger: logging.Logger = None,
):
    """
    Decorador para reintentar una función en caso de excepción.

    Args:
        exceptions (tuple): Tupla de excepciones que se deben reintentar.
        max_retries (int, optional): Número máximo de reintentos. Defaults to 3.
        backoff_factor (float, optional): Factor de retardo para el tiempo de espera. Defaults to 0.5.
        logger (logging.Logger, optional): Logger para registrar errores. Defaults to None.

    Raises:
        Exception: La excepción original si todos los reintentos fallan.
    """

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if not isinstance(max_retries, int) or max_retries < 0:
                raise ValueError("max_retries debe ser un número entero no negativo")
            if backoff_factor <= 0:
                raise ValueError("backoff_factor debe ser mayor que 0")
            if not exceptions:
                raise ValueError("exceptions no puede ser vacío")
            if logger is not None and not isinstance(logger, logging.Logger):
                raise ValueError("logger debe ser un objeto logging.Logger")

            delay = 0
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    if attempt < max_retries:
                        delay = backoff_factor * (2 ** attempt)
                        delay_with_jitter = delay * (1 + random.random() * 0.1)
                        if logger:
                            logger.warning(
                                f"Reintento {attempt + 1}/{max_retries} en {delay_with_jitter:.2f} segundos"
                            )
                        time.sleep(delay_with_jitter)
                    else:
                        if logger:
                            logger.error(f"Todos los reintentos fallaron: {e}")
                        raise Exception(f"Todos los reintentos fallaron: {e}") from e

        return wrapper

    return decorator
